+        let ext = MdlExtractor::new(MdlConfig {
+            min_confidence: 0.0,
+            ..Default::default()
+        });
+        let result = ext.extract(&window);
+        if !result.commands.is_empty() {
+            prop_assert!(
+                result.commands.last().unwrap().is_success(),
+                "Last extracted command should be successful"
+            );
+        }
+    }
+}
